import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getSession } from "@/lib/session";
import { successResponse, errorResponse } from "@/lib/api-response";

// GET /api/hospitals/costs - Get all costs catalog
export async function GET(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const costs = await prisma.treatmentCost.findMany({
      where: { hospitalId: hospital.id },
      orderBy: { treatmentName: "asc" },
    });

    return successResponse({ costs });
  } catch (error: any) {
    console.error("GET /api/hospitals/costs error:", error);
    return errorResponse("Failed to fetch treatment costs", 500);
  }
}

// POST /api/hospitals/costs - Add new treatment catalog item
export async function POST(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const body = await request.json();
    const { treatmentName, department, minCost, maxCost, insuranceCovered, description } = body;

    const cost = await prisma.treatmentCost.create({
      data: {
        hospitalId: hospital.id,
        treatmentName,
        department,
        minCost: Number(minCost),
        maxCost: Number(maxCost),
        insuranceCovered: Boolean(insuranceCovered),
        description,
      },
    });

    return successResponse({ cost });
  } catch (error: any) {
    console.error("POST /api/hospitals/costs error:", error);
    return errorResponse("Failed to add treatment catalog item", 500);
  }
}

// PUT /api/hospitals/costs - Edit treatment catalog item
export async function PUT(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const body = await request.json();
    const { id, treatmentName, department, minCost, maxCost, insuranceCovered, description } = body;

    // Verify ownership
    const existingCost = await prisma.treatmentCost.findFirst({
      where: { id, hospitalId: hospital.id },
    });

    if (!existingCost) {
      return errorResponse("Treatment catalog item not found", 404);
    }

    const updatedCost = await prisma.treatmentCost.update({
      where: { id },
      data: {
        treatmentName,
        department,
        minCost: Number(minCost),
        maxCost: Number(maxCost),
        insuranceCovered: Boolean(insuranceCovered),
        description,
      },
    });

    return successResponse({ cost: updatedCost });
  } catch (error: any) {
    console.error("PUT /api/hospitals/costs error:", error);
    return errorResponse("Failed to update treatment catalog item", 500);
  }
}

// DELETE /api/hospitals/costs - Remove item
export async function DELETE(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital not found", 404);
    }

    const { searchParams } = new URL(request.url);
    const id = searchParams.get("id");

    if (!id) {
      return errorResponse("Item ID is required", 400);
    }

    // Verify ownership
    const existingCost = await prisma.treatmentCost.findFirst({
      where: { id, hospitalId: hospital.id },
    });

    if (!existingCost) {
      return errorResponse("Item not found", 404);
    }

    await prisma.treatmentCost.delete({
      where: { id },
    });

    return successResponse({ message: "Treatment cost catalog item deleted successfully" });
  } catch (error: any) {
    console.error("DELETE /api/hospitals/costs error:", error);
    return errorResponse("Failed to delete item", 500);
  }
}
